/* eslint-disable import/no-cycle */
/* eslint-disable import/prefer-default-export */
/* eslint-disable wrap-iife */
/* eslint-disable import/no-self-import */
/* eslint-disable import/named */
import { initLudo } from '@/main'
import { initBloot } from '@@/main'
import { initDiwania } from '@d/main'
import { getArgsFromUrl } from '@badam/common-utils'
import { fb } from './fb'

// baloot 传的是 bundleid
// ludo diwania 传的是 bundle_id
const bundle_id = getArgsFromUrl('bundle_id') || getArgsFromUrl('bundleid') || 'com.sawa.ludo'

function initBtn() {
  ;(function (d, s, id) {
    let js: any
    let fjs: any = d.getElementsByTagName(s)[0]
    if (d.getElementById(id)) {
      return
    }
    js = d.createElement(s)
    js.id = id
    js.src = 'https://connect.facebook.net/en_US/sdk.js'
    if (fjs) fjs.parentNode.insertBefore(js, fjs)
  })(document, 'script', 'facebook-jssdk')
  ;(window as any).fbAsyncInit = function () {
    // 这里不改了，登录sawa都走 297601757621370
    const pkg = getArgsFromUrl('bundleid')
    fb.appid = pkg === 'com.sawa.ksa' ? '391521625027907' : '297601757621370'
    console.log('facebook初始化 包名', pkg, fb.appid)
    const v = 'v6.0'
    ;(window as any).FB.init({
      appId: fb.appid,
      xfbml: true,
      version: v,
    })
    ;(window as any).FB.AppEvents.logPageView()
  }
}

if (bundle_id === 'hk.longchiu.dwn') {
  initDiwania()
} else if (bundle_id === 'com.sawa.ksa') {
  initBloot()
} else {
  initLudo()
}

initBtn()
